B.Yd=new A.a0("Verileri nas\u0131l kullan\u0131r\u0131z?","Verilerini sana en uygun profilleri g\xf6stermek, e\u015fle\u015fmeleri kurmak, g\xfcvenli\u011fi sa\u011flamak ve hizmeti geli\u015ftirmek i\xe7in kullan\u0131r\u0131z. \u0130zin vermedik\xe7e pazarlama amac\u0131yla \xfc\xe7\xfcnc\xfc taraflarla payla\u015fmay\u0131z.")
B.XM=new A.a0("Payla\u015f\u0131m","Profilinde g\xf6sterdi\u011fin bilgiler di\u011fer kullan\u0131c\u0131larca g\xf6r\xfclebilir. Yasal y\xfck\xfcml\xfcl\xfckler d\u0131\u015f\u0131nda ki\u015fisel verilerini satmay\u0131z.")
B.Yc=new A.a0("G\xfcvenlik","Verilerin \u015fifreli olarak saklan\u0131r ve yetkisiz eri\u015fime kar\u015f\u0131 korunur. Yine de hi\xe7bir sistem %100 g\xfcvenli de\u011fildir; g\xfc\xe7l\xfc bir \u015fifre kullanman\u0131 \xf6neririz.")
B.XN=new A.a0("Haklar\u0131n\u0131z","Verilerine eri\u015fme, d\xfczeltme ve silme talebinde bulunabilirsin. Hesab\u0131n\u0131 sildi\u011finde verilerin makul s\xfcre i\xe7inde kal\u0131c\u0131 olarak silinir.")
B.Xr=new A.a0("\u0130leti\u015fim","Gizlilikle ilgili sorular i\xe7in destek@makelove.app adresine yazabilirsin.")
B.SK=s([B.XQ,B.Yd,B.XM,B.Yc,B.XN,B.Xr],t.Wy)
B.a9r=new A.Bi("Gizlilik Politikas\u0131",B.SK)
B.XL=new A.a0("Uygunluk","Make Love\u2019\u0131 yaln\u0131zca 18 ya\u015f\u0131n\u0131 doldurmu\u015f ki\u015filer kullanabilir. Hesap olu\u015fturarak 18 ya\u015f\u0131ndan b\xfcy\xfck oldu\u011funu beyan edersin.")
B.Y5=new A.a0("Hesab\u0131n","Hesap bilgilerinin gizlili\u011finden ve hesab\u0131nda ger\xe7ekle\u015fen t\xfcm etkinliklerden sen sorumlusun. Bir ba\u015fkas\u0131 ad\u0131na sahte profil olu\u015fturamazs\u0131n.")
B.XX=new A.a0("Davran\u0131\u015f kurallar\u0131","Taciz, nefret s\xf6ylemi, sahtek\xe2rl\u0131k, spam ve yasa d\u0131\u015f\u0131 i\xe7erik kesinlikle yasakt\u0131r. Bu kurallar\u0131 ihlal eden hesaplar uyar\u0131s\u0131z kapat\u0131labilir.")
B.XV=new A.a0("Abonelikler","Premium abonelikler ilgili ma\u011faza (App Store / Google Play) \xfczerinden faturaland\u0131r\u0131l\u0131r ve otomatik yenilenir. \u0130ptal ma\u011faza ayarlar\u0131ndan yap\u0131l\u0131r.")
B.Y2=new A.a0("Sorumluluk reddi","Make Love bir tan\u0131\u015fma platformudur; kullan\u0131c\u0131lar aras\u0131ndaki etkile\u015fimlerden veya bulu\u015fmalardan do\u011fan durumlardan sorumlu de\u011fildir. G\xfcvenlik ipu\xe7lar\u0131m\u0131za uy.")
B.Y9=new A.a0("De\u011fi\u015fiklikler","Bu ko\u015fullar\u0131 zaman zaman g\xfcncelleyebiliriz. \xd6nemli de\u011fi\u015fikliklerde seni bilgilendiririz; kullanmaya devam etmen g\xfcncel ko\u015fullar\u0131 kabul etti\u011fin anlam\u0131na gelir.")
B.PV=s([B.XL,B.Y5,B.XX,B.XV,B.Y2,B.Y9],t.Wy)
B.a9s=new A.Bi("Kullan\u0131m Ko\u015fullar\u0131",B.PV)
B.Xz=new A.a0("Veri sorumlusu","6698 say\u0131l\u0131 Ki\u015fisel Verilerin Korunmas\u0131 Kanunu (KVKK) kapsam\u0131nda ki\u015fisel verilerin, veri sorumlusu s\u0131fat\u0131yla Make Love taraf\u0131ndan a\u015fa\u011f\u0131da a\xe7\u0131klanan ama\xe7larla i\u015flenmektedir.")
B.Xv=new A.a0("\u0130\u015flenen ki\u015fisel veriler","Kimlik (ad, ya\u015f, cinsiyet), ileti\u015fim (e-posta), profil ve kullan\u0131m verileri (ilgi alanlar\u0131, e\u015fle\u015fmeler, mesajlar) i\u015flenmektedir.")
B.XE=new A.a0("\u0130\u015fleme ama\xe7lar\u0131","Verilerin; \xfcyelik kayd\u0131n\u0131n olu\u015fturulmas\u0131, e\u015fle\u015ftirme hizmetinin sunulmas\u0131, g\xfcvenli\u011fin sa\u011flanmas\u0131 ve yasal y\xfck\xfcml\xfcl\xfcklerin yerine getirilmesi amac\u0131yla i\u015flenir.")
B.XC=new A.a0("Hukuki sebep","Veriler, KVKK m.5 uyar\u0131nca s\xf6zle\u015fmenin kurulmas\u0131/ifas\u0131, me\u015fru menfaat ve a\xe7\u0131k r\u0131za hukuki sebeplerine dayan\u0131larak i\u015flenir.")
B.XH=new A.a0("Haklar\u0131n\u0131z (KVKK m.11)","Ki\u015fisel verilerinin i\u015flenip i\u015flenmedi\u011fini \xf6\u011frenme, d\xfczeltilmesini veya silinmesini isteme, i\u015flemeye itiraz etme ve zarar\u0131n giderilmesini talep etme haklar\u0131na sahipsin.")
B.XF=new A.a0("Ba\u015fvuru","KVKK kapsam\u0131ndaki taleplerini destek@makelove.app adresine iletebilirsin. Ba\u015fvurun en ge\xe7 30 g\xfcn i\xe7inde sonu\xe7land\u0131r\u0131l\u0131r.")
B.Sv=s([B.Xz,B.Xv,B.XE,B.XC,B.XH,B.XF],t.Wy)
B.a9t=new A.Bi("KVKK Ayd\u0131nlatma Metni",B.Sv)
